'use client';

// src/app/arvo-offer/page.tsx
// Branded ARVO price-offer builder. Paste the offer text into the editable body,
// auto offer-number + date fill in, then "Save as PDF" (browser print). Ferrari
// port of the standalone ARVO_price_offer_template.html — now a real app route.
import { useEffect, useRef } from 'react';

const ARVO_LOGO = 'data:image/png;base64,';

const STYLE = `
  .arvo-root{--gold:#c9a23f;--gold-soft:#e6c870;--ink:#1a1a1a;--charcoal:#222;--paper:#fff;--muted:#6b6b6b;--line:#e5e2da;background:#f3f2ee;font-family:'Heebo',system-ui,sans-serif;color:var(--ink);min-height:100vh;}
  .arvo-root *{box-sizing:border-box;-webkit-print-color-adjust:exact;print-color-adjust:exact;}
  .arvo-toolbar{position:sticky;top:0;z-index:50;background:#1a1a1a;color:#fff;display:flex;gap:10px;align-items:center;flex-wrap:wrap;padding:10px 16px;}
  .arvo-toolbar .hint{font-size:13px;color:#cfcabd;margin-inline-start:auto;}
  .arvo-btn{border:0;border-radius:8px;padding:9px 16px;font-size:14px;font-weight:700;cursor:pointer;font-family:inherit;}
  .arvo-btn-gold{background:linear-gradient(180deg,#e6c870,#c9a23f);color:#1a1a1a;}
  .arvo-btn-ghost{background:#333;color:#fff;}
  .arvo-page{max-width:794px;margin:18px auto;background:var(--paper);box-shadow:0 6px 30px rgba(0,0,0,.12);min-height:1123px;display:flex;flex-direction:column;}
  .arvo-head{background:#161616;color:#fff;padding:26px 40px;display:flex;align-items:center;gap:22px;border-bottom:3px solid var(--gold);}
  .arvo-head img{width:96px;height:auto;border-radius:6px;}
  .arvo-brand{display:flex;flex-direction:column;}
  .arvo-brand .name{font-family:'Frank Ruhl Libre',serif;font-weight:900;color:#fff;font-size:26px;line-height:1.1;}
  .arvo-brand .tag{font-family:'Frank Ruhl Libre',serif;color:var(--gold-soft);font-size:13px;letter-spacing:.5px;margin-top:2px;}
  .arvo-contact{margin-inline-start:auto;text-align:left;font-size:12px;line-height:1.7;color:#d9d4c7;direction:ltr;}
  .arvo-contact .vat{color:var(--gold-soft);font-weight:500;}
  .arvo-meta{display:flex;justify-content:space-between;align-items:center;padding:16px 40px;border-bottom:1px solid var(--line);background:#faf9f6;}
  .arvo-meta .offno{font-weight:700;font-size:15px;color:var(--charcoal);}
  .arvo-meta .offno span{color:var(--gold);}
  .arvo-meta .date{font-size:13px;color:var(--muted);}
  .arvo-body{flex:1;padding:30px 40px;}
  .arvo-body-edit{white-space:pre-wrap;font-size:15px;line-height:1.85;color:#222;min-height:520px;outline:none;border:1px dashed transparent;border-radius:8px;padding:6px;}
  .arvo-body-edit:focus{border-color:var(--gold);background:#fffdf6;}
  .arvo-body-edit:empty:before{content:'\\2190 הדבק כאן את הצעת המחיר (מהטקסט שהעתקת והגהת)';color:#bbb;font-style:italic;}
  .arvo-foot{padding:18px 40px;border-top:2px solid var(--gold);background:#161616;color:#cfcabd;font-size:12px;display:flex;justify-content:space-between;align-items:center;direction:ltr;}
  .arvo-foot .he{direction:rtl;font-family:'Frank Ruhl Libre',serif;color:var(--gold-soft);}
  @media print{
    .arvo-root{background:#fff;}
    .arvo-toolbar{display:none !important;}
    .arvo-page{box-shadow:none;margin:0;max-width:none;width:100%;min-height:auto;}
    @page{size:A4;margin:0;}
  }
`;

export default function ArvoOfferPage() {
  const bodyRef = useRef<HTMLDivElement>(null);
  const offnoRef = useRef<HTMLSpanElement>(null);
  const dateRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    const d = new Date();
    const pad = (n: number) => String(n).padStart(2, '0');
    const ymd = d.getFullYear() + pad(d.getMonth() + 1) + pad(d.getDate());
    const hm = pad(d.getHours()) + pad(d.getMinutes());
    if (offnoRef.current) offnoRef.current.textContent = 'ARVO-' + ymd + '-' + hm;
    if (dateRef.current) dateRef.current.textContent = 'תאריך: ' + pad(d.getDate()) + '.' + pad(d.getMonth() + 1) + '.' + d.getFullYear() + ' · ' + pad(d.getHours()) + ':' + pad(d.getMinutes());
  }, []);

  function onPaste(e: React.ClipboardEvent<HTMLDivElement>) {
    e.preventDefault();
    const t = (e.clipboardData || (window as unknown as { clipboardData: DataTransfer }).clipboardData).getData('text/plain');
    document.execCommand('insertText', false, t);
  }

  return (
    <div className="arvo-root" dir="rtl">
      <style dangerouslySetInnerHTML={{ __html: STYLE }} />
      <div className="arvo-toolbar">
        <button className="arvo-btn arvo-btn-gold" onClick={() => window.print()}>📄 שמור כ-PDF</button>
        <button className="arvo-btn arvo-btn-ghost" onClick={() => bodyRef.current?.focus()}>✏️ ערוך טקסט</button>
        <span className="hint">הדבק את ההצעה ← ערוך אם צריך ← שמור כ-PDF</span>
      </div>

      <div className="arvo-page">
        <div className="arvo-head">
          {/* eslint-disable-next-line @next/next/no-img-element */}
          <img src={ARVO_LOGO} alt="ARVO" />
          <div className="arvo-brand">
            <div className="name">א.ק עבודות גמר</div>
            <div className="tag">ARVO · כיורי שיש מעוצבים</div>
          </div>
          <div className="arvo-contact">
            <div>Aalless1290@gmail.com</div>
            <div>Tel: 050-402-9723</div>
            <div className="vat">עוסק מורשה 317017804</div>
          </div>
        </div>

        <div className="arvo-meta">
          <div className="offno">הצעה מס׳ <span ref={offnoRef}></span></div>
          <div className="date" ref={dateRef}></div>
        </div>

        <div className="arvo-body">
          <div className="arvo-body-edit" contentEditable suppressContentEditableWarning ref={bodyRef} onPaste={onPaste}></div>
        </div>

        <div className="arvo-foot">
          <div>Aalless1290@gmail.com · 050-402-9723 · עוסק מורשה 317017804</div>
          <div className="he">א.ק עבודות גמר — ARVO</div>
        </div>
      </div>
    </div>
  );
}
